import React, { useEffect, useState } from "react";
import API from "../../api/api";
import { useNavigate } from "react-router-dom";

export default function Projects() {
  const navigate = useNavigate();
  const [proposals, setProposals]     = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading]         = useState(true);
  const [modal, setModal]             = useState(null);
  const [form, setForm]               = useState({ description:"", github_link:"", live_link:"" });
  const [submitting, setSubmitting]   = useState(false);
  const [success, setSuccess]         = useState("");

  useEffect(() => {
    Promise.all([API.get("/proposals/my"), API.get("/submissions/my")])
      .then(([pr, sr]) => {
        setProposals((pr.data||[]).filter(p => p.status === "accepted"));
        setSubmissions(sr.data||[]);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  const getSub = (pid) => submissions.find(s => s.project_id === pid);

  const handleSubmit = async () => {
    if (!form.description) return alert("Description is required");
    setSubmitting(true);
    try {
      await API.post("/submissions", {
        project_id:  modal.project_id,
        description: form.description,
        github_link: form.github_link,
        live_link:   form.live_link,
      });
      const r = await API.get("/submissions/my");
      setSubmissions(r.data||[]);
      setSuccess("Work submitted successfully!");
      setTimeout(() => { setSuccess(""); setModal(null); }, 1500);
    } catch(e) { alert(e.response?.data?.message || "Error"); }
    setSubmitting(false);
  };

  const statusStyle = (s) => {
    const m = {
      approved:  { bg:"#dcfce7", color:"#15803d", border:"#86efac" },
      revision:  { bg:"#fff7ed", color:"#c2410c", border:"#fed7aa" },
      submitted: { bg:"#eff6ff", color:"#1d4ed8", border:"#bfdbfe" },
    };
    return m[s] || m.submitted;
  };

  const inp = {
    width:"100%", padding:"10px 12px",
    border:"1.5px solid #e2e8f0", borderRadius:"8px",
    fontSize:"13px", outline:"none",
    background:"white", color:"#0f172a",
    boxSizing:"border-box",
  };
  const lbl = {
    fontSize:"11px", fontWeight:"700", color:"#64748b",
    display:"block", marginBottom:"4px",
    textTransform:"uppercase", letterSpacing:"0.8px",
  };

  if (loading) return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center" }}>
      <span style={{ color:"#0f766e", fontWeight:"600", fontSize:"15px" }}>Loading...</span>
    </div>
  );

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" }}>

      <h1 style={{ fontSize:"24px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>My Projects</h1>
      <p style={{ fontSize:"13px", color:"#64748b", marginBottom:"28px" }}>Submit your completed work for client review</p>

      {/* SUCCESS BANNER */}
      {success && (
        <div style={{ background:"#dcfce7", border:"1px solid #86efac", color:"#15803d", padding:"12px 16px", borderRadius:"10px", marginBottom:"16px", fontSize:"13px", fontWeight:"600" }}>
          🎉 {success}
        </div>
      )}

      {/* EMPTY STATE */}
      {proposals.length === 0 ? (
        <div style={{ background:"white", borderRadius:"14px", padding:"60px", textAlign:"center", border:"1px solid #e2e8f0", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>
          <div style={{ fontSize:"40px", marginBottom:"12px" }}>📭</div>
          <p style={{ color:"#94a3b8", marginBottom:"16px", fontSize:"14px" }}>No accepted projects yet.</p>
          <button onClick={() => navigate("/freelancer/find-projects")}
            style={{ padding:"10px 22px", borderRadius:"9px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"13px", fontWeight:"700", cursor:"pointer" }}>
            Browse Projects
          </button>
        </div>
      ) : proposals.map(p => {
        const sub = getSub(p.project_id);
        const ss  = sub ? statusStyle(sub.status) : null;
        return (
          <div key={p.id} style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"12px", padding:"20px", marginBottom:"12px", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>

            {/* TOP ROW */}
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"12px" }}>
              <div>
                <h3 style={{ fontSize:"15px", fontWeight:"700", color:"#0f172a", margin:"0 0 5px" }}>
                  {p.project_title}
                </h3>
                <div style={{ display:"flex", gap:"16px", fontSize:"13px" }}>
                  <span style={{ color:"#64748b" }}>
                    Budget: <strong style={{ color:"#0f172a" }}>₹{p.project_budget || p.budget}</strong>
                  </span>
                  <span style={{ color:"#0f766e", fontWeight:"700" }}>Your Bid: ₹{p.bid}</span>
                </div>
              </div>

              {/* ACTION BUTTON */}
              {!sub ? (
                <button
                  onClick={() => { setModal(p); setForm({ description:"", github_link:"", live_link:"" }); }}
                  style={{ padding:"9px 18px", borderRadius:"8px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"12px", fontWeight:"700", cursor:"pointer", flexShrink:0 }}>
                  🚀 Submit Work
                </button>
              ) : sub.status === "revision" ? (
                <button
                  onClick={() => { setModal(p); setForm({ description:sub.description||"", github_link:sub.github_link||"", live_link:sub.live_link||"" }); }}
                  style={{ padding:"9px 18px", borderRadius:"8px", border:"none", background:"linear-gradient(135deg,#d97706,#b45309)", color:"white", fontSize:"12px", fontWeight:"700", cursor:"pointer", flexShrink:0 }}>
                  🔄 Resubmit
                </button>
              ) : (
                <span style={{ padding:"6px 14px", borderRadius:"8px", border:"1px solid #bbf7d0", color:"#16a34a", fontSize:"12px", fontWeight:"700", background:"#f0fdf4" }}>
                  Submitted ✓
                </span>
              )}
            </div>

            {/* SUBMISSION DETAILS */}
            {sub && ss && (
              <div style={{ background:"#f8fafc", border:"1px solid #e2e8f0", borderRadius:"10px", padding:"14px", marginTop:"8px" }}>
                <span style={{ background:ss.bg, color:ss.color, border:`1px solid ${ss.border}`, fontSize:"10px", fontWeight:"700", padding:"3px 12px", borderRadius:"20px", textTransform:"capitalize", display:"inline-block", marginBottom:"8px" }}>
                  {sub.status}
                </span>

                {sub.description && (
                  <p style={{ fontSize:"13px", color:"#64748b", margin:"0 0 8px", lineHeight:1.5 }}>{sub.description}</p>
                )}

                <div style={{ display:"flex", gap:"14px" }}>
                  {sub.github_link && (
                    <a href={sub.github_link} target="_blank" rel="noreferrer"
                      style={{ color:"#0891b2", fontSize:"12px", fontWeight:"600", textDecoration:"none" }}>
                      🔗 GitHub
                    </a>
                  )}
                  {sub.live_link && (
                    <a href={sub.live_link} target="_blank" rel="noreferrer"
                      style={{ color:"#0f766e", fontSize:"12px", fontWeight:"600", textDecoration:"none" }}>
                      🌐 Live Demo
                    </a>
                  )}
                </div>

                {sub.feedback && (
                  <div style={{ marginTop:"10px", background:"#fff7ed", border:"1px solid #fed7aa", borderRadius:"8px", padding:"10px", fontSize:"12px", color:"#c2410c" }}>
                    💬 Client Feedback: {sub.feedback}
                  </div>
                )}

                {sub.status === "approved" && (
                  <div style={{ marginTop:"10px", background:"#dcfce7", border:"1px solid #86efac", borderRadius:"8px", padding:"10px", fontSize:"12px", color:"#15803d", fontWeight:"600" }}>
                    ✅ Project Approved! Great work!
                  </div>
                )}
              </div>
            )}
          </div>
        );
      })}

      {/* SUBMIT MODAL */}
      {modal && (
        <div
          style={{ position:"fixed", inset:0, background:"rgba(15,23,42,0.5)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:50, padding:"20px" }}
          onClick={e => e.target === e.currentTarget && setModal(null)}>
          <div style={{ background:"white", borderRadius:"16px", padding:"28px", width:"100%", maxWidth:"440px", boxShadow:"0 20px 60px rgba(0,0,0,0.15)" }}>

            {success ? (
              <div style={{ textAlign:"center", padding:"20px" }}>
                <div style={{ fontSize:"40px", marginBottom:"10px" }}>🎉</div>
                <p style={{ color:"#15803d", fontWeight:"700", fontSize:"16px" }}>{success}</p>
              </div>
            ) : (
              <>
                <h2 style={{ fontSize:"18px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>Submit Your Work</h2>
                <p style={{ fontSize:"12px", color:"#64748b", marginBottom:"20px" }}>{modal.project_title}</p>

                <div style={{ marginBottom:"14px" }}>
                  <label style={lbl}>Work Description <span style={{ color:"#ef4444" }}>*</span></label>
                  <textarea value={form.description} onChange={e => setForm({...form, description:e.target.value})}
                    rows={3} placeholder="Describe what you built..."
                    style={{ ...inp, resize:"none", lineHeight:1.5 }} />
                </div>

                <div style={{ marginBottom:"14px" }}>
                  <label style={lbl}>🔗 GitHub Repository</label>
                  <input type="url" value={form.github_link} onChange={e => setForm({...form, github_link:e.target.value})}
                    placeholder="https://github.com/username/repo" style={inp} />
                </div>

                <div style={{ marginBottom:"20px" }}>
                  <label style={lbl}>🌐 Live Demo <span style={{ color:"#94a3b8", fontWeight:"400", textTransform:"none" }}>(optional)</span></label>
                  <input type="url" value={form.live_link} onChange={e => setForm({...form, live_link:e.target.value})}
                    placeholder="https://yourproject.vercel.app" style={inp} />
                </div>

                <div style={{ display:"flex", gap:"10px" }}>
                  <button onClick={handleSubmit} disabled={submitting}
                    style={{ flex:1, padding:"11px", borderRadius:"9px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontWeight:"700", cursor:submitting?"not-allowed":"pointer", opacity:submitting?.7:1 }}>
                    {submitting ? "Submitting..." : "Submit Project"}
                  </button>
                  <button onClick={() => setModal(null)}
                    style={{ padding:"11px 18px", borderRadius:"9px", border:"1px solid #e2e8f0", background:"white", color:"#64748b", cursor:"pointer" }}>
                    Cancel
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
